function componente(id) {
  for (const cat of Object.keys(BIBLIOTECA)) {
    const c = BIBLIOTECA[cat].find((x) => x.id === id);
    if (c) return c;
  }
  return null;
}
const idsDe = (cat) => (BIBLIOTECA[cat] || []).map((c) => c.id);

module.exports = { BIBLIOTECA, componente, idsDe };
